import type { CheckpointQuestion, Highlight, Level, StoryCharacter, StoryComprehensionCheck, StoryMessage, WhatsAppStory } from "../../types";

const skoolReturnUrl = "https://www.skool.com/agedown-transform-after-50-7367/classroom/f616edc2?md=67cdf40fda5d436a821d6fdeb584d97d";

type HighlightSeed = [phrase: string, meaning: string, note?: string];
type MessageSeed = {
  speakerId: string;
  text: string;
  translation: string;
  vocab: HighlightSeed[];
  grammar?: HighlightSeed[];
};
type CheckSeed = {
  question: string;
  options: [string, string, string, string];
  correct: string;
  explanation: string;
  skill: string;
};

function highlights(seeds: HighlightSeed[]): Highlight[] {
  return seeds.map(([phrase, meaning, note]) => ({ phrase, meaning, note }));
}

function grammarHighlights(seeds?: HighlightSeed[]): Highlight[] | undefined {
  return seeds?.map(([phrase, meaning, note]) => ({ phrase, explanation: `${meaning}${note ? ` ${note}` : ""}` }));
}

function messages(seeds: MessageSeed[]): StoryMessage[] {
  return seeds.map((seed, index) => ({
    id: `m${index + 1}`,
    speakerId: seed.speakerId,
    text: seed.text,
    translation: seed.translation,
    vocabHighlights: highlights(seed.vocab),
    grammarHighlights: grammarHighlights(seed.grammar),
  }));
}

function checks(seeds: CheckSeed[]): StoryComprehensionCheck[] {
  return seeds.map((seed, index) => ({
    id: `check-${index + 1}`,
    afterMessageId: `m${(index + 1) * 3}`,
    question: {
      id: `q-${index + 1}`,
      type: "multiple-choice",
      prompt: seed.question,
      options: seed.options,
      correctAnswer: seed.correct,
      explanation: seed.explanation,
      points: 1,
      skillTag: seed.skill,
    } satisfies CheckpointQuestion,
  }));
}

function story({
  id,
  title,
  subtitle,
  level,
  tags,
  characters,
  messageSeeds,
  checkSeeds,
  learnedVocab,
  keyPhrases,
  grammarPatterns,
  speakingPrompts,
  completionInstructions,
}: {
  id: string;
  title: string;
  subtitle: string;
  level: Level;
  tags: string[];
  characters: StoryCharacter[];
  messageSeeds: MessageSeed[];
  checkSeeds: CheckSeed[];
  learnedVocab: string[];
  keyPhrases: string[];
  grammarPatterns: string[];
  speakingPrompts: string[];
  completionInstructions: string;
}): WhatsAppStory {
  return {
    id,
    title,
    subtitle,
    languageTarget: "english",
    learnerNativeLanguage: "spanish",
    level,
    tags: ["Historias por Chat en Inglés — A1 a C2", "whatsapp-style-chat", ...tags],
    estimatedMinutes: 8,
    skoolSectionName: "Historias por Chat en Inglés — A1 a C2",
    skoolReturnUrl,
    activityType: "story",
    data: {
      targetLanguage: "english",
      nativeLanguage: "spanish",
      characters,
      messages: messages(messageSeeds),
      comprehensionChecks: checks(checkSeeds),
      learnedVocab,
      finalReview: { keyPhrases, grammarPatterns, speakingPrompts },
      completionTask: { title: "Tarea final", instructions: completionInstructions },
    },
  };
}

